import{_ as o,o as i,c as a,ag as l}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"概要 | Dotfiles (JA)","titleTemplate":":title","description":"Chezmoiで管理される次世代の設定ファイル。高性能、安全、AIネイティブ。 macOS・Linux・WSL対応。Dotfilesで管理。","frontmatter":{"title":"概要 | Dotfiles","description":"Chezmoiで管理される次世代の設定ファイル。高性能、安全、AIネイティブ。 macOS・Linux・WSL対応。Dotfilesで管理。","lang":"ja-JP","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"概要 preview","canonical":"/ja/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"概要","pageType":"docs","schemaType":"WebPage","metaTitle":"概要 - Dotfiles (JA)","permalink":"/ja/about/","meta":[{"name":"keywords","content":"chezmoi, dotfiles, 設定, 自動化, macos, linux, rust, zellij"}]},"headers":[],"relativePath":"ja/about/index.md","filePath":"ja/about/index.md","lastUpdated":1773010926000}'),d={name:"ja/about/index.md"};function t(c,e,s,r,n,h){return i(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="dotfiles-v0-2-495-について" tabindex="-1">Dotfiles v0.2.495 について <a class="header-anchor" href="#dotfiles-v0-2-495-について" aria-label="Permalink to &quot;Dotfiles v0.2.495 について&quot;">​</a></h1><h2 id="はじめに" tabindex="-1">はじめに <a class="header-anchor" href="#はじめに" aria-label="Permalink to &quot;はじめに&quot;">​</a></h2><p>Dotfilesは環境設定のモダンスタンダードです。<strong>Chezmoi</strong>上に構築され、シェル、アプリケーション、シークレットを安全かつ信頼性高くクロスプラットフォームで管理できます。</p><p>複雑なMakefileやシンボリックリンクスクリプトに依存するレガシーなdotfilesとは異なり、Dotfilesはアトミックで高速なテンプレートベースのアプローチを使用します。</p><h2 id="v0-2-495の新機能" tabindex="-1">v0.2.495の新機能 <a class="header-anchor" href="#v0-2-495の新機能" aria-label="Permalink to &quot;v0.2.495の新機能&quot;">​</a></h2><ul><li><strong>モダンコア</strong>: レガシーUnixツールを高性能Rust代替品に置き換え: <ul><li><strong>Atuin</strong> (<code>history</code>を置換)</li><li><strong>Yazi</strong> (<code>ls</code>/<code>ranger</code>を置換)</li><li><strong>Zellij</strong> (<code>tmux</code>を置換)</li><li><strong>Ghostty</strong> (モダンGPUアクセラレーテッドターミナル)</li><li><strong>NeoVim</strong> (モダンVimベースエディタ)</li></ul></li><li><strong>ネイティブセキュリティ</strong>: サードパーティエージェントなしの完全ネイティブSSH署名。</li><li><strong>インタラクティブモード</strong>: 新しい<code>dot learn</code>コマンドで機能をガイド。</li></ul><h2 id="インストール" tabindex="-1">インストール <a class="header-anchor" href="#インストール" aria-label="Permalink to &quot;インストール&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><h2 id="検証" tabindex="-1">検証 <a class="header-anchor" href="#検証" aria-label="Permalink to &quot;検証&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="コアコマンド" tabindex="-1">コアコマンド <a class="header-anchor" href="#コアコマンド" aria-label="Permalink to &quot;コアコマンド&quot;">​</a></h2><ul><li><code>dot apply</code> 設定変更を適用します。</li><li><code>dot update</code> リポジトリを更新し、キャッシュをウォームアップします。</li><li><code>dot doctor</code> パス、ツール、シェルの状態を検証します。</li><li><code>dot heal</code> 欠落または壊れた状態を修復します。</li><li><code>dot smoke-test</code> コアツールチェーンを検証します。</li></ul><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="/ja/aliases/">エイリアス</a></li><li><a href="/ja/functions/">関数</a></li><li><a href="/ja/paths/">パス</a></li></ul><h2 id="コアコマンド-1" tabindex="-1">コアコマンド <a class="header-anchor" href="#コアコマンド-1" aria-label="Permalink to &quot;コアコマンド&quot;">​</a></h2><p><code>dot</code> CLI は 53 のコマンドをカテゴリ別に提供します。</p><h3 id="コア" tabindex="-1">コア <a class="header-anchor" href="#コア" aria-label="Permalink to &quot;コア&quot;">​</a></h3><ul><li><code>dot apply</code> — 設定変更を適用します.</li><li><code>dot sync</code> — 最新のリポジトリ状態を取得して適用します.</li><li><code>dot update</code> — リポジトリを更新しキャッシュをウォームアップします.</li><li><code>dot add</code> — 新しいファイルを Chezmoi ソースに追加します.</li><li><code>dot diff</code> — 適用前の保留中の変更を表示します.</li><li><code>dot status</code> — 管理対象ファイルのステータスを表示します.</li><li><code>dot remove</code> — ファイルの管理を解除しソースエントリを削除します.</li><li><code>dot cd</code> — Chezmoi ソースディレクトリ内でシェルを開きます.</li><li><code>dot edit</code> — 管理対象ファイルをエディタで開きます.</li><li><code>dot clean-cache</code> — 一時キャッシュを消去します.</li><li><code>dot prewarm</code> — シェルの高速起動のためにキャッシュを事前準備します.</li></ul><h3 id="診断" tabindex="-1">診断 <a class="header-anchor" href="#診断" aria-label="Permalink to &quot;診断&quot;">​</a></h3><ul><li><code>dot doctor</code> — パス、ツール、シェルの状態を検証します.</li><li><code>dot heal</code> — 欠落または破損した状態を自動的に修復します.</li><li><code>dot health</code> — 軽量なヘルスプローブを実行します.</li><li><code>dot verify</code> — ソースに対するファイルの整合性を確認します.</li><li><code>dot scorecard</code> — 設定品質スコアを表示します.</li><li><code>dot snapshot</code> — 後の比較のために現在の状態をキャプチャします.</li><li><code>dot smoke-test</code> — コアツールチェーンをエンドツーエンドで検証します.</li><li><code>dot chaos</code> — 自己修復をテストするために障害を注入します.</li><li><code>dot bundle</code> — ポータブルな設定バンドルをエクスポートします.</li><li><code>dot rollback</code> — 以前のスナップショットに戻します.</li><li><code>dot drift</code> — 管理対象ファイルへの予期しない変更を検出します.</li><li><code>dot history</code> — apply/sync の履歴ログを表示します.</li><li><code>dot benchmark</code> — シェルの起動時間を測定します.</li><li><code>dot perf</code> — シェル初期化の遅延をプロファイリングします.</li></ul><h3 id="外観" tabindex="-1">外観 <a class="header-anchor" href="#外観" aria-label="Permalink to &quot;外観&quot;">​</a></h3><ul><li><code>dot theme</code> — ターミナルのカラースキームを切り替えます.</li><li><code>dot wallpaper</code> — デスクトップの壁紙を設定します（macOS）.</li><li><code>dot fonts</code> — Nerd Fonts をインストールまたは更新します.</li><li><code>dot tune</code> — UI の密度とプロンプトスタイルを調整します.</li></ul><h3 id="セキュリティ" tabindex="-1">セキュリティ <a class="header-anchor" href="#セキュリティ" aria-label="Permalink to &quot;セキュリティ&quot;">​</a></h3><ul><li><code>dot backup</code> — 暗号化された設定バックアップを作成します.</li><li><code>dot encrypt-check</code> — 保存時のシークレット暗号化を検証します.</li><li><code>dot firewall</code> — ホストファイアウォールルールを設定します.</li><li><code>dot telemetry</code> — 匿名使用テレメトリを制御します.</li><li><code>dot dns-doh</code> — DNS-over-HTTPS を有効にします.</li><li><code>dot lock-screen</code> — 画面を即座にロックします.</li><li><code>dot usb-safety</code> — USB マスストレージの自動マウントを制限します.</li></ul><h3 id="シークレット" tabindex="-1">シークレット <a class="header-anchor" href="#シークレット" aria-label="Permalink to &quot;シークレット&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — シークレットバックエンドを初期化します（age / GPG）.</li><li><code>dot secrets</code> — 暗号化されたシークレットエントリを一覧表示します.</li><li><code>dot secrets-create</code> — 新しい暗号化シークレットを作成します.</li><li><code>dot ssh-key</code> — SSH 鍵ペアを生成またはローテーションします.</li><li><code>dot ssh-cert</code> — CA から SSH 証明書を要求します.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — インタラクティブな AI アシスタントセッションを開きます.</li><li><code>dot ai-setup</code> — AI プロバイダの API キーを設定します.</li><li><code>dot ai-query</code> — AI モデルにワンショットプロンプトを送信します.</li><li>AI ツールラッパー: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="ツール" tabindex="-1">ツール <a class="header-anchor" href="#ツール" aria-label="Permalink to &quot;ツール&quot;">​</a></h3><ul><li><code>dot tools</code> — バンドルされた CLI 代替ツールとそのステータスを一覧表示します.</li><li><code>dot new</code> — 新しいエイリアスまたは関数ファイルを作成します.</li><li><code>dot sandbox</code> — 使い捨てサンドボックスシェルを開きます.</li><li><code>dot keys</code> — 現在のキーバインドを表示します.</li><li><code>dot learn</code> — インタラクティブチュートリアルを開始します.</li></ul><h3 id="メタ" tabindex="-1">メタ <a class="header-anchor" href="#メタ" aria-label="Permalink to &quot;メタ&quot;">​</a></h3><ul><li><code>dot upgrade</code> — Dotfiles を最新リリースにアップグレードします.</li><li><code>dot packages</code> — Dotfiles が管理するインストール済みパッケージを一覧表示します.</li><li><code>dot version</code> / <code>dot help</code> — バージョンまたは使用方法の情報を表示します</li></ul>',32)])])}const b=o(d,[["render",t]]);export{p as __pageData,b as default};
